#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, K;
        scanf("%lld %lld", &N, &K);
        printf("%lld\n", K / N);
    }
    return 0;
}

